import React, { useState, useEffect, useRef } from 'react';
import { useTranslation } from 'react-i18next';
import StatsSection from '../components/StatsSection';
import NewsSection from '../components/NewsSection';
import '../styles/CoursesPage.css';

const CoursesPage = () => {
    const { t } = useTranslation();
    const [isVisible, setIsVisible] = useState(false);
    const [selectedCourse, setSelectedCourse] = useState(null);
    const [isModalOpen, setIsModalOpen] = useState(false);
    const [activeFilter, setActiveFilter] = useState('all');
    const sectionRef = useRef(null);

    // Sample course data
    const courses = [
        {
            id: 1,
            title: "Full Stack Web Development",
            category: "web-development",
            level: "Beginner to Advanced",
            duration: "12 weeks",
            price: "$299",
            rating: 4.9,
            students: 1250,
            image: require('../assets/images/png5.jpg'),
            instructor: "John Smith",
            description: "Master modern web development with React, Node.js, and MongoDB",
            fullDescription: "This comprehensive course covers everything from HTML/CSS basics to advanced React patterns, backend development with Node.js and Express, database design with MongoDB, and deployment strategies. You'll build 5 real-world projects including an e-commerce platform.",
            skills: ["React", "Node.js", "MongoDB", "Express", "JavaScript", "HTML/CSS"],
            curriculum: [
                "Frontend Fundamentals (HTML, CSS, JavaScript)",
                "React Development & State Management",
                "Backend Development with Node.js",
                "Database Design & MongoDB",
                "API Development & Integration",
                "Deployment & DevOps"
            ],
            prerequisites: ["Basic computer skills", "Problem-solving mindset"],
            certificate: true,
            support: "24/7 Community Support"
        },
        {
            id: 2,
            title: "Data Science & Analytics",
            category: "data-science",
            level: "Intermediate",
            duration: "16 weeks",
            price: "$399",
            rating: 4.8,
            students: 980,
            image: require('../assets/images/png5.jpg'),
            instructor: "Dr. Sarah Johnson",
            description: "Learn Python, machine learning, and data visualization techniques",
            fullDescription: "Dive deep into data science with Python, statistical analysis, machine learning algorithms, and data visualization. Work with real datasets and build predictive models that solve business problems.",
            skills: ["Python", "Pandas", "NumPy", "Scikit-learn", "Matplotlib", "Seaborn"],
            curriculum: [
                "Python for Data Science",
                "Statistical Analysis & Probability",
                "Data Cleaning & Preprocessing",
                "Machine Learning Algorithms",
                "Data Visualization",
                "Capstone Project"
            ],
            prerequisites: ["Basic programming knowledge", "Mathematics background"],
            certificate: true,
            support: "Mentor-guided learning"
        },
        {
            id: 3,
            title: "Cybersecurity Fundamentals",
            category: "cybersecurity",
            level: "Beginner",
            duration: "10 weeks",
            price: "$249",
            rating: 4.7,
            students: 750,
            image: require('../assets/images/png5.jpg'),
            instructor: "Michael Chen",
            description: "Protect digital assets and learn ethical hacking techniques",
            fullDescription: "Master cybersecurity fundamentals including network security, ethical hacking, risk assessment, and security frameworks. Hands-on labs with real-world scenarios.",
            skills: ["Network Security", "Ethical Hacking", "Risk Assessment", "Security Frameworks"],
            curriculum: [
                "Introduction to Cybersecurity",
                "Network Security Fundamentals",
                "Ethical Hacking & Penetration Testing",
                "Risk Management",
                "Security Compliance",
                "Incident Response"
            ],
            prerequisites: ["Basic networking knowledge"],
            certificate: true,
            support: "Industry expert mentorship"
        }
    ];

    const filteredCourses = activeFilter === 'all' 
        ? courses 
        : courses.filter(course => course.category === activeFilter);

    useEffect(() => {
        setIsVisible(true);

        const createCubes = () => {
            const world = document.querySelector('.world');
            if (!world) return;

            for (let i = 0; i < 15; i++) {
                const cube = document.createElement('div');
                cube.className = 'cube';

                const x = (Math.random() - 0.5) * 1000;
                const y = (Math.random() - 0.5) * 1000;
                const z = (Math.random() - 0.5) * 1000;
                const size = Math.random() * 50 + 20;

                cube.style.width = `${size}px`;
                cube.style.height = `${size}px`;
                cube.style.transform = `translate3d(${x}px, ${y}px, ${z}px)`;

                ['front', 'back', 'right', 'left', 'top', 'bottom'].forEach(face => {
                    const el = document.createElement('div');
                    el.className = `cube-face ${face}`;
                    cube.appendChild(el);
                });

                world.appendChild(cube);
            }
        };

        createCubes();

        return () => {
            const world = document.querySelector('.world');
            if (world) {
                while (world.firstChild) {
                    world.removeChild(world.firstChild);
                }
            }
        };
    }, []);

    const openModal = (course) => {
        setSelectedCourse(course);
        setIsModalOpen(true);
    };

    const closeModal = () => {
        setIsModalOpen(false);
        setSelectedCourse(null);
    };

    return (
        <div className="courses-page">
            {/* Hero Section - Keep existing structure */}
            <section ref={sectionRef} className={`courses-hero ${isVisible ? 'visible' : ''}`}>
                <div className="scene">
                    <div className="world">
                        <div className="floor"></div>
                    </div>
                    <div className="glow glow-1"></div>
                    <div className="glow glow-2"></div>
                </div>

                <div className="container">
                    <div className="hero-content">
                        <div className="hero-text">
                            <div className="hero-badge">
                                <span className="badge-icon material-icons">school</span>
                                {t('courses.hero.badge')}
                            </div>
                            <h1 className="hero-title">{t('courses.hero.title')} <span className="highlight-text">{t('courses.hero.highlight')}</span></h1>
                            <p className="hero-description">{t('courses.hero.description')}</p>

                            <div className="hero-cta-group">
                                <button className="btn btn-primary">
                                    <span className="material-icons">search</span>
                                    {t('courses.hero.findCourse')}
                                </button>
                                <button className="btn btn-outline">
                                    <span className="material-icons">info</span>
                                    {t('courses.hero.programGuide')}
                                </button>
                            </div>

                            <div className="hero-stats">
                                <div className="stat-item">
                                    <div className="stat-number">30+</div>
                                    <div className="stat-label">{t('courses.stats.courses')}</div>
                                </div>
                                <div className="stat-item">
                                    <div className="stat-number">95%</div>
                                    <div className="stat-label">{t('courses.stats.jobPlacement')}</div>
                                </div>
                                <div className="stat-item">
                                    <div className="stat-number">4.9</div>
                                    <div className="stat-label">{t('courses.stats.studentRating')}</div>
                                </div>
                            </div>
                        </div>

                        <div className="hero-image-wrapper">
                            <div className="image-card">
                                <img 
                                    src={require('../assets/images/png5.jpg')} 
                                    alt={t('courses.hero.imageAlt')} 
                                    className="hero-image" 
                                />
                                <div className="image-overlay"></div>
                                <div className="tech-tag-group">
                                    <div className="tech-tag">{t('courses.webDevelopment')}</div>
                                    <div className="tech-tag">{t('courses.dataScience')}</div>
                                    <div className="tech-tag">{t('courses.cybersecurity')}</div>
                                    <div className="tech-tag">{t('courses.cloudComputing')}</div>
                                </div>
                            </div>
                        </div>
                    </div>
                </div>
            </section>

            {/* Course Filters */}
            <div id="courses" className="course-filters-container">
                <div className="container">
                    <div className="flex flex-wrap justify-center gap-4 mb-12">
                        <button 
                            onClick={() => setActiveFilter('all')}
                            className={`px-6 py-3 rounded-full font-medium transition-all duration-300 flex items-center gap-2 ${
                                activeFilter === 'all' 
                                    ? 'bg-gradient-to-r from-blue-500 to-purple-600 text-white shadow-lg' 
                                    : 'bg-white text-gray-700 hover:bg-gray-50 border border-gray-200'
                            }`}
                        >
                            <span className="material-icons text-sm">school</span>
                            All Categories
                        </button>
                        <button 
                            onClick={() => setActiveFilter('web-development')}
                            className={`px-6 py-3 rounded-full font-medium transition-all duration-300 flex items-center gap-2 ${
                                activeFilter === 'web-development' 
                                    ? 'bg-gradient-to-r from-blue-500 to-purple-600 text-white shadow-lg' 
                                    : 'bg-white text-gray-700 hover:bg-gray-50 border border-gray-200'
                            }`}
                        >
                            <span className="material-icons text-sm">code</span>
                            Web Development
                        </button>
                        <button 
                            onClick={() => setActiveFilter('data-science')}
                            className={`px-6 py-3 rounded-full font-medium transition-all duration-300 flex items-center gap-2 ${
                                activeFilter === 'data-science' 
                                    ? 'bg-gradient-to-r from-blue-500 to-purple-600 text-white shadow-lg' 
                                    : 'bg-white text-gray-700 hover:bg-gray-50 border border-gray-200'
                            }`}
                        >
                            <span className="material-icons text-sm">analytics</span>
                            Data Science
                        </button>
                        <button 
                            onClick={() => setActiveFilter('cybersecurity')}
                            className={`px-6 py-3 rounded-full font-medium transition-all duration-300 flex items-center gap-2 ${
                                activeFilter === 'cybersecurity' 
                                    ? 'bg-gradient-to-r from-blue-500 to-purple-600 text-white shadow-lg' 
                                    : 'bg-white text-gray-700 hover:bg-gray-50 border border-gray-200'
                            }`}
                        >
                            <span className="material-icons text-sm">security</span>
                            Cybersecurity
                        </button>
                    </div>
                </div>
            </div>

            {/* Courses Grid */}
            <section className="py-20 bg-gray-50">
                <div className="container mx-auto px-4">
                    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
                        {filteredCourses.map((course) => (
                            <div 
                                key={course.id} 
                                className="bg-white rounded-2xl shadow-lg hover:shadow-2xl transition-all duration-500 transform hover:-translate-y-2 group overflow-hidden"
                            >
                                <div className="relative overflow-hidden">
                                    <img 
                                        src={course.image} 
                                        alt={course.title}
                                        className="w-full h-48 object-cover group-hover:scale-110 transition-transform duration-500"
                                    />
                                    <div className="absolute top-4 right-4 bg-white bg-opacity-90 px-3 py-1 rounded-full text-sm font-bold text-gray-800">
                                        {course.price}
                                    </div>
                                    <div className="absolute top-4 left-4 bg-gradient-to-r from-blue-500 to-purple-600 text-white px-3 py-1 rounded-full text-sm font-medium">
                                        {course.level}
                                    </div>
                                </div>

                                <div className="p-6">
                                    <div className="flex items-center justify-between mb-2">
                                        <span className="text-sm text-gray-500 capitalize">
                                            {course.category.replace('-', ' ')}
                                        </span>
                                        <div className="flex items-center gap-1">
                                            <span className="material-icons text-yellow-400 text-sm">star</span>
                                            <span className="text-sm font-medium">{course.rating}</span>
                                        </div>
                                    </div>

                                    <h3 className="text-xl font-bold text-gray-900 mb-3 group-hover:text-blue-600 transition-colors">
                                        {course.title}
                                    </h3>

                                    <p className="text-gray-600 mb-4 text-sm leading-relaxed">
                                        {course.description}
                                    </p>

                                    <div className="flex items-center justify-between mb-4">
                                        <div className="flex items-center gap-2 text-sm text-gray-500">
                                            <span className="material-icons text-sm">schedule</span>
                                            {course.duration}
                                        </div>
                                        <div className="flex items-center gap-2 text-sm text-gray-500">
                                            <span className="material-icons text-sm">people</span>
                                            {course.students} students
                                        </div>
                                    </div>

                                    <div className="flex gap-3">
                                        <button 
                                            onClick={() => openModal(course)}
                                            className="flex-1 bg-gradient-to-r from-blue-500 to-purple-600 text-white py-3 px-4 rounded-xl font-medium hover:from-blue-600 hover:to-purple-700 transition-all duration-300 flex items-center justify-center gap-2"
                                        >
                                            <span className="material-icons text-sm">info</span>
                                            Learn More
                                        </button>
                                        <button className="px-4 py-3 border-2 border-gray-200 rounded-xl hover:border-blue-500 hover:text-blue-500 transition-all duration-300">
                                            <span className="material-icons">favorite_border</span>
                                        </button>
                                    </div>
                                </div>
                            </div>
                        ))}
                    </div>
                </div>
            </section>

            {/* Course Modal */}
            {isModalOpen && selectedCourse && (
                <div className="fixed inset-0 bg-black bg-opacity-50 z-50 flex items-center justify-center p-4">
                    <div className="bg-white rounded-3xl max-w-4xl w-full max-h-[90vh] overflow-y-auto transform transition-all duration-300 scale-100">
                        {/* Modal Header */}
                        <div className="relative">
                            <img 
                                src={selectedCourse.image} 
                                alt={selectedCourse.title}
                                className="w-full h-64 object-cover rounded-t-3xl"
                            />
                            <button 
                                onClick={closeModal}
                                className="absolute top-4 right-4 bg-white bg-opacity-90 hover:bg-opacity-100 rounded-full p-2 transition-all duration-300"
                            >
                                <span className="material-icons">close</span>
                            </button>
                            <div className="absolute bottom-4 left-6 bg-white bg-opacity-95 px-4 py-2 rounded-full">
                                <span className="text-2xl font-bold text-gray-900">{selectedCourse.price}</span>
                            </div>
                        </div>

                        <div className="p-8">
                            {/* Course Title & Basic Info */}
                            <div className="mb-6">
                                <div className="flex items-center gap-3 mb-4">
                                    <span className="bg-gradient-to-r from-blue-500 to-purple-600 text-white px-3 py-1 rounded-full text-sm font-medium">
                                        {selectedCourse.level}
                                    </span>
                                    <div className="flex items-center gap-1">
                                        <span className="material-icons text-yellow-400">star</span>
                                        <span className="font-medium">{selectedCourse.rating}</span>
                                        <span className="text-gray-500">({selectedCourse.students} students)</span>
                                    </div>
                                </div>

                                <h2 className="text-3xl font-bold text-gray-900 mb-2">{selectedCourse.title}</h2>
                                <p className="text-gray-600 text-lg">{selectedCourse.fullDescription}</p>
                            </div>

                            {/* Course Details Grid */}
                            <div className="grid md:grid-cols-2 gap-8 mb-8">
                                {/* Left Column */}
                                <div>
                                    <h3 className="text-xl font-bold text-gray-900 mb-4">What You'll Learn</h3>
                                    <div className="space-y-3">
                                        {selectedCourse.curriculum.map((item, index) => (
                                            <div key={index} className="flex items-start gap-3">
                                                <span className="material-icons text-green-500 text-sm mt-1">check_circle</span>
                                                <span className="text-gray-700">{item}</span>
                                            </div>
                                        ))}
                                    </div>
                                </div>

                                {/* Right Column */}
                                <div>
                                    <h3 className="text-xl font-bold text-gray-900 mb-4">Course Details</h3>
                                    <div className="space-y-4">
                                        <div className="flex items-center gap-3">
                                            <span className="material-icons text-blue-500">schedule</span>
                                            <div>
                                                <span className="font-medium">Duration:</span>
                                                <span className="text-gray-600 ml-2">{selectedCourse.duration}</span>
                                            </div>
                                        </div>

                                        <div className="flex items-center gap-3">
                                            <span className="material-icons text-blue-500">person</span>
                                            <div>
                                                <span className="font-medium">Instructor:</span>
                                                <span className="text-gray-600 ml-2">{selectedCourse.instructor}</span>
                                            </div>
                                        </div>

                                        <div className="flex items-center gap-3">
                                            <span className="material-icons text-blue-500">support</span>
                                            <div>
                                                <span className="font-medium">Support:</span>
                                                <span className="text-gray-600 ml-2">{selectedCourse.support}</span>
                                            </div>
                                        </div>

                                        {selectedCourse.certificate && (
                                            <div className="flex items-center gap-3">
                                                <span className="material-icons text-blue-500">workspace_premium</span>
                                                <span className="font-medium">Certificate of Completion</span>
                                            </div>
                                        )}
                                    </div>
                                </div>
                            </div>

                            {/* Skills Tags */}
                            <div className="mb-8">
                                <h3 className="text-xl font-bold text-gray-900 mb-4">Technologies & Skills</h3>
                                <div className="flex flex-wrap gap-2">
                                    {selectedCourse.skills.map((skill, index) => (
                                        <span 
                                            key={index}
                                            className="bg-gradient-to-r from-blue-100 to-purple-100 text-blue-800 px-3 py-2 rounded-full text-sm font-medium"
                                        >
                                            {skill}
                                        </span>
                                    ))}
                                </div>
                            </div>

                            {/* Prerequisites */}
                            <div className="mb-8">
                                <h3 className="text-xl font-bold text-gray-900 mb-4">Prerequisites</h3>
                                <div className="space-y-2">
                                    {selectedCourse.prerequisites.map((prereq, index) => (
                                        <div key={index} className="flex items-center gap-3">
                                            <span className="material-icons text-orange-500 text-sm">info</span>
                                            <span className="text-gray-700">{prereq}</span>
                                        </div>
                                    ))}
                                </div>
                            </div>

                            {/* Action Buttons */}
                            <div className="flex gap-4">
                                <button className="flex-1 bg-gradient-to-r from-blue-500 to-purple-600 text-white py-4 px-6 rounded-xl font-bold text-lg hover:from-blue-600 hover:to-purple-700 transition-all duration-300 flex items-center justify-center gap-2">
                                    <span className="material-icons">play_circle</span>
                                    Enroll Now
                                </button>
                                <button className="px-6 py-4 border-2 border-gray-200 rounded-xl hover:border-blue-500 hover:text-blue-500 transition-all duration-300 flex items-center gap-2">
                                    <span className="material-icons">bookmark_border</span>
                                    Save for Later
                                </button>
                            </div>
                        </div>
                    </div>
                </div>
            )}

            {/* Keep existing sections */}
            <section className="stats-section">
                <div className="container">
                    <StatsSection />
                </div>
            </section>

            <section className="news-section">
                <div className="container">
                    <div className="section-header">
                        <h2>{t('courses.news.title')}</h2>
                        <p>{t('courses.news.description')}</p>
                    </div>
                    <NewsSection />
                </div>
            </section>
        </div>
    );
};

export default CoursesPage;
